/* login.html edit 19/08/06 */
i>svg{
	display: block;
	width: 100%;
	height: 100%;
}
input[type="text"]{
	transform: translate3d(0, 0, 0);
}
input[type="button"]{
	cursor: pointer;
}
.login{
	background: #f5f5f5;
}
.bg_login{
	width: 100%;
	min-height: 100%;
	padding-bottom: 16px;
	background: #f5f5f5;
	flex: none;
	min-height: 100dvh;
	/*
	background: url('../images/bg_login.jpg') no-repeat;
	background-position: center 56px;
	*/
}
.ios15 .bg_login{
	height: -webkit-fit-content;
	padding-bottom: calc(env(safe-area-inset-bottom) + 16px);
}
.box_language{
	width: 100%;
	height: 56px;
	line-height: 56px;
	text-align: center;
	font-size: 14px;
	background: #503f32;
}
.btn_language{
	display: inline-block;
	width: 33.33%;
	height: 100%;
	max-width: 107px;
	margin-right: -4px;
	cursor: pointer;
	color: rgba(255, 255, 255, 0.72);
	transition: all 0.3s ease;
}
.btn_language.on{
	color: #debb69;
}
.icon_login{
	display: block;
	width: 55px;
	height: 55px;
	margin: 16px auto;
	border-radius: 50%;
	background: url(../images/icon_login.svg) no-repeat;
	background-size: contain;
}
.box_login{
	width: 100%;
	max-width: 320px;
	margin: 16px auto;
	padding: 24px 16px 16px 16px;
	text-align: center;
	background: #fff;
	/* box-shadow: 0 -1px 20px 0 rgba(0, 0, 0, 0.24); */
}
.lab_input{
	position: relative;
	display: block;
	width: 100%;
	height: 48px;
	margin-bottom: 16px;
}
.input_chgpwd .lab_input{
	margin-bottom: 0;
}
.lab_input>input{
	display: block;
	width: 100%;
	height: 100%;
	margin: 0;
	padding: 0 32px 0 16px;
	font-size: 16px;
	border-radius: 4px;
	border: 1px solid rgba(0, 0, 0, 0.32);
	color: #000;
	box-shadow: none;
	transition: all 0.3s ease;
	pointer-events: auto;
}

input.userid,
.text_user,
span.oth_pass_hello{
	font-family: 'Tahoma', 'Verdana', serif;
}

